/**
 * Chess piece classes and their movement rules
 * Defines all 6 piece types with their specific movement patterns
 */

const PieceType = {
    PAWN: 'pawn',
    ROOK: 'rook',
    KNIGHT: 'knight',
    BISHOP: 'bishop',
    QUEEN: 'queen',
    KING: 'king'
};

const PieceColor = {
    WHITE: 'white',
    BLACK: 'black'
};

/**
 * Base Piece class
 */
class Piece {
    constructor(color, type, row, col) {
        this.color = color;
        this.type = type;
        this.row = row;
        this.col = col;
        this.hasMoved = false;
    }

    /**
     * Get all possible moves for this piece
     * @param {Board} board - The game board
     * @returns {Array} Array of valid position objects
     */
    getValidMoves(board) {
        return [];
    }

    /**
     * Check if a position is valid and not occupied by own piece
     * @param {number} row - Target row
     * @param {number} col - Target column
     * @param {Board} board - The game board
     * @returns {boolean} True if position is valid for move
     */
    isValidPosition(row, col, board) {
        if (!Position.isValid(row, col)) {
            return false;
        }

        const targetPiece = board.getPieceAt(row, col);
        return !targetPiece || targetPiece.color !== this.color;
    }

    /**
     * Clone this piece
     * @returns {Piece} New piece with same properties
     */
    clone() {
        const piece = new Piece(this.color, this.type, this.row, this.col);
        piece.hasMoved = this.hasMoved;
        return piece;
    }
}

/**
 * Pawn class - forward movement, diagonal capture
 */
class Pawn extends Piece {
    constructor(color, row, col) {
        super(color, PieceType.PAWN, row, col);
        this.direction = color === PieceColor.WHITE ? -1 : 1;
        this.startRow = color === PieceColor.WHITE ? 6 : 1;
    }

    getValidMoves(board) {
        const moves = [];
        const direction = this.direction;

        // Forward move
        const forwardRow = this.row + direction;
        if (Position.isValid(forwardRow, this.col) && !board.getPieceAt(forwardRow, this.col)) {
            moves.push({ row: forwardRow, col: this.col });

            // Double move from starting position
            if (this.row === this.startRow) {
                const doubleRow = this.row + 2 * direction;
                if (Position.isValid(doubleRow, this.col) && !board.getPieceAt(doubleRow, this.col)) {
                    moves.push({ row: doubleRow, col: this.col });
                }
            }
        }

        // Diagonal captures
        for (const colOffset of [-1, 1]) {
            const captureRow = this.row + direction;
            const captureCol = this.col + colOffset;

            if (Position.isValid(captureRow, captureCol)) {
                const targetPiece = board.getPieceAt(captureRow, captureCol);
                if (targetPiece && targetPiece.color !== this.color) {
                    moves.push({ row: captureRow, col: captureCol });
                }
            }
        }

        // En passant
        if (board.enPassantTarget) {
            const epPos = Position.fromAlgebraic(board.enPassantTarget);
            if (epPos && epPos.row === this.row + direction && Math.abs(epPos.col - this.col) === 1) {
                moves.push({ row: epPos.row, col: epPos.col, isEnPassant: true });
            }
        }

        return moves;
    }

    clone() {
        const pawn = new Pawn(this.color, this.row, this.col);
        pawn.hasMoved = this.hasMoved;
        return pawn;
    }
}

/**
 * Rook class - horizontal and vertical movement
 */
class Rook extends Piece {
    constructor(color, row, col) {
        super(color, PieceType.ROOK, row, col);
    }

    getValidMoves(board) {
        const moves = [];
        const directions = [
            { row: -1, col: 0 },  // up
            { row: 1, col: 0 },   // down
            { row: 0, col: -1 },  // left
            { row: 0, col: 1 }    // right
        ];

        for (const dir of directions) {
            let newRow = this.row + dir.row;
            let newCol = this.col + dir.col;

            while (Position.isValid(newRow, newCol)) {
                const targetPiece = board.getPieceAt(newRow, newCol);

                if (!targetPiece) {
                    moves.push({ row: newRow, col: newCol });
                } else {
                    if (targetPiece.color !== this.color) {
                        moves.push({ row: newRow, col: newCol });
                    }
                    break; // Blocked by piece
                }

                newRow += dir.row;
                newCol += dir.col;
            }
        }

        return moves;
    }

    clone() {
        const rook = new Rook(this.color, this.row, this.col);
        rook.hasMoved = this.hasMoved;
        return rook;
    }
}

/**
 * Knight class - L-shaped movement
 */
class Knight extends Piece {
    constructor(color, row, col) {
        super(color, PieceType.KNIGHT, row, col);
    }

    getValidMoves(board) {
        const moves = [];
        const offsets = [
            { row: -2, col: -1 }, { row: -2, col: 1 },
            { row: -1, col: -2 }, { row: -1, col: 2 },
            { row: 1, col: -2 }, { row: 1, col: 2 },
            { row: 2, col: -1 }, { row: 2, col: 1 }
        ];

        for (const offset of offsets) {
            const newRow = this.row + offset.row;
            const newCol = this.col + offset.col;

            if (this.isValidPosition(newRow, newCol, board)) {
                moves.push({ row: newRow, col: newCol });
            }
        }

        return moves;
    }

    clone() {
        return new Knight(this.color, this.row, this.col);
    }
}

/**
 * Bishop class - diagonal movement
 */
class Bishop extends Piece {
    constructor(color, row, col) {
        super(color, PieceType.BISHOP, row, col);
    }

    getValidMoves(board) {
        const moves = [];
        const directions = [
            { row: -1, col: -1 },  // up-left
            { row: -1, col: 1 },   // up-right
            { row: 1, col: -1 },   // down-left
            { row: 1, col: 1 }     // down-right
        ];

        for (const dir of directions) {
            let newRow = this.row + dir.row;
            let newCol = this.col + dir.col;

            while (Position.isValid(newRow, newCol)) {
                const targetPiece = board.getPieceAt(newRow, newCol);

                if (!targetPiece) {
                    moves.push({ row: newRow, col: newCol });
                } else {
                    if (targetPiece.color !== this.color) {
                        moves.push({ row: newRow, col: newCol });
                    }
                    break; // Blocked by piece
                }

                newRow += dir.row;
                newCol += dir.col;
            }
        }

        return moves;
    }

    clone() {
        return new Bishop(this.color, this.row, this.col);
    }
}

/**
 * Queen class - combined rook and bishop movement
 */
class Queen extends Piece {
    constructor(color, row, col) {
        super(color, PieceType.QUEEN, row, col);
    }

    getValidMoves(board) {
        const moves = [];
        const directions = [
            { row: -1, col: 0 },  // up
            { row: 1, col: 0 },   // down
            { row: 0, col: -1 },  // left
            { row: 0, col: 1 },   // right
            { row: -1, col: -1 },  // up-left
            { row: -1, col: 1 },   // up-right
            { row: 1, col: -1 },   // down-left
            { row: 1, col: 1 }     // down-right
        ];

        for (const dir of directions) {
            let newRow = this.row + dir.row;
            let newCol = this.col + dir.col;

            while (Position.isValid(newRow, newCol)) {
                const targetPiece = board.getPieceAt(newRow, newCol);

                if (!targetPiece) {
                    moves.push({ row: newRow, col: newCol });
                } else {
                    if (targetPiece.color !== this.color) {
                        moves.push({ row: newRow, col: newCol });
                    }
                    break; // Blocked by piece
                }

                newRow += dir.row;
                newCol += dir.col;
            }
        }

        return moves;
    }

    clone() {
        return new Queen(this.color, this.row, this.col);
    }
}

/**
 * King class - one square movement, castling
 */
class King extends Piece {
    constructor(color, row, col) {
        super(color, PieceType.KING, row, col);
    }

    getValidMoves(board) {
        const moves = [];
        const offsets = [
            { row: -1, col: -1 }, { row: -1, col: 0 }, { row: -1, col: 1 },
            { row: 0, col: -1 },                        { row: 0, col: 1 },
            { row: 1, col: -1 },  { row: 1, col: 0 },  { row: 1, col: 1 }
        ];

        for (const offset of offsets) {
            const newRow = this.row + offset.row;
            const newCol = this.col + offset.col;

            if (this.isValidPosition(newRow, newCol, board)) {
                moves.push({ row: newRow, col: newCol });
            }
        }

        return moves;
    }

    clone() {
        const king = new King(this.color, this.row, this.col);
        king.hasMoved = this.hasMoved;
        return king;
    }
}

/**
 * Factory function to create pieces
 */
function createPiece(color, type, row, col) {
    switch (type) {
        case PieceType.PAWN:
            return new Pawn(color, row, col);
        case PieceType.ROOK:
            return new Rook(color, row, col);
        case PieceType.KNIGHT:
            return new Knight(color, row, col);
        case PieceType.BISHOP:
            return new Bishop(color, row, col);
        case PieceType.QUEEN:
            return new Queen(color, row, col);
        case PieceType.KING:
            return new King(color, row, col);
        default:
            throw new Error(`Unknown piece type: ${type}`);
    }
}

/**
 * Get piece symbol for display
 */
function getPieceSymbol(type, color) {
    const symbols = {
        white: {
            pawn: '♟',
            rook: '♜',
            knight: '♞',
            bishop: '♝',
            queen: '♛',
            king: '♚'
        },
        black: {
            pawn: '♙',
            rook: '♖',
            knight: '♘',
            bishop: '♗',
            queen: '♕',
            king: '♔'
        }
    };
    return symbols[color][type];
}

/**
 * Get piece value for evaluation
 */
function getPieceValue(type) {
    const values = {
        pawn: 1,
        knight: 3,
        bishop: 3,
        rook: 5,
        queen: 9,
        king: 0 // King is invaluable
    };
    return values[type];
}

