/**
 * Position utility functions for chess game
 * Handles conversion between algebraic notation and array coordinates
 */

class Position {
    /**
     * Convert algebraic notation (e.g., "e4") to array coordinates
     * @param {string} algebraic - Algebraic notation like "e4"
     * @returns {Object} Object with row and col properties
     */
    static fromAlgebraic(algebraic) {
        if (!algebraic || algebraic.length !== 2) {
            return null;
        }

        const col = algebraic.charCodeAt(0) - 97; // 'a' = 0, 'b' = 1, etc.
        const row = 8 - parseInt(algebraic[1]); // '8' = 0, '1' = 7

        if (col < 0 || col > 7 || row < 0 || row > 7) {
            return null;
        }

        return { row, col };
    }

    /**
     * Convert array coordinates to algebraic notation
     * @param {number} row - Row index (0-7)
     * @param {number} col - Column index (0-7)
     * @returns {string} Algebraic notation like "e4"
     */
    static toAlgebraic(row, col) {
        if (row < 0 || row > 7 || col < 0 || col > 7) {
            return null;
        }

        const file = String.fromCharCode(97 + col); // 0 = 'a', 1 = 'b', etc.
        const rank = 8 - row; // 0 = '8', 7 = '1'

        return file + rank;
    }

    /**
     * Check if a position is valid (on the board)
     * @param {number} row - Row index
     * @param {number} col - Column index
     * @returns {boolean} True if position is valid
     */
    static isValid(row, col) {
        return row >= 0 && row <= 7 && col >= 0 && col <= 7;
    }

    /**
     * Check if two positions are equal
     * @param {Object} pos1 - First position {row, col}
     * @param {Object} pos2 - Second position {row, col}
     * @returns {boolean} True if positions are equal
     */
    static equals(pos1, pos2) {
        return pos1 && pos2 && pos1.row === pos2.row && pos1.col === pos2.col;
    }

    /**
     * Create a position object
     * @param {number} row - Row index
     * @param {number} col - Column index
     * @returns {Object} Position object {row, col}
     */
    static create(row, col) {
        return { row, col };
    }

    /**
     * Add two positions (for move calculations)
     * @param {Object} pos1 - First position
     * @param {Object} pos2 - Second position (as offset)
     * @returns {Object} New position
     */
    static add(pos1, pos2) {
        return {
            row: pos1.row + pos2.row,
            col: pos1.col + pos2.col
        };
    }

    /**
     * Get all positions between two positions (exclusive)
     * @param {Object} from - Start position
     * @param {Object} to - End position
     * @returns {Array} Array of positions between
     */
    static getBetween(from, to) {
        const positions = [];
        const rowDiff = Math.sign(to.row - from.row);
        const colDiff = Math.sign(to.col - from.col);

        let current = { row: from.row + rowDiff, col: from.col + colDiff };

        while (!Position.equals(current, to)) {
            positions.push({ ...current });
            current = {
                row: current.row + rowDiff,
                col: current.col + colDiff
            };
        }

        return positions;
    }

    /**
     * Calculate distance between two positions
     * @param {Object} pos1 - First position
     * @param {Object} pos2 - Second position
     * @returns {number} Manhattan distance
     */
    static distance(pos1, pos2) {
        return Math.abs(pos1.row - pos2.row) + Math.abs(pos1.col - pos2.col);
    }
}

// Export for use in other modules
if (typeof module !== 'undefined' && module.exports) {
    module.exports = Position;
}

