/**
 * Tests for Position utility class
 */

const Position = require('./position');

describe('Position', () => {
  describe('fromAlgebraic', () => {
    test('should convert standard algebraic notation to coordinates', () => {
      expect(Position.fromAlgebraic('e4')).toEqual({ row: 4, col: 4 });
      expect(Position.fromAlgebraic('a1')).toEqual({ row: 7, col: 0 });
      expect(Position.fromAlgebraic('h8')).toEqual({ row: 0, col: 7 });
    });

    test('should return null for invalid notation', () => {
      expect(Position.fromAlgebraic('i9')).toBeNull();
      expect(Position.fromAlgebraic('')).toBeNull();
      expect(Position.fromAlgebraic('e')).toBeNull();
      expect(Position.fromAlgebraic('e44')).toBeNull();
    });

    test('should handle edge cases', () => {
      expect(Position.fromAlgebraic('a8')).toEqual({ row: 0, col: 0 });
      expect(Position.fromAlgebraic('h1')).toEqual({ row: 7, col: 7 });
    });
  });

  describe('toAlgebraic', () => {
    test('should convert coordinates to algebraic notation', () => {
      expect(Position.toAlgebraic(4, 4)).toBe('e4');
      expect(Position.toAlgebraic(7, 0)).toBe('a1');
      expect(Position.toAlgebraic(0, 7)).toBe('h8');
    });

    test('should return null for invalid coordinates', () => {
      expect(Position.toAlgebraic(-1, 0)).toBeNull();
      expect(Position.toAlgebraic(8, 0)).toBeNull();
      expect(Position.toAlgebraic(0, -1)).toBeNull();
      expect(Position.toAlgebraic(0, 8)).toBeNull();
    });

    test('should handle edge cases', () => {
      expect(Position.toAlgebraic(0, 0)).toBe('a8');
      expect(Position.toAlgebraic(7, 7)).toBe('h1');
    });
  });

  describe('isValid', () => {
    test('should return true for valid positions', () => {
      expect(Position.isValid(0, 0)).toBe(true);
      expect(Position.isValid(7, 7)).toBe(true);
      expect(Position.isValid(4, 4)).toBe(true);
    });

    test('should return false for invalid positions', () => {
      expect(Position.isValid(-1, 0)).toBe(false);
      expect(Position.isValid(8, 0)).toBe(false);
      expect(Position.isValid(0, -1)).toBe(false);
      expect(Position.isValid(0, 8)).toBe(false);
    });
  });

  describe('equals', () => {
    test('should return true for equal positions', () => {
      expect(Position.equals({ row: 4, col: 4 }, { row: 4, col: 4 })).toBe(true);
    });

    test('should return false for different positions', () => {
      expect(Position.equals({ row: 4, col: 4 }, { row: 3, col: 4 })).toBe(false);
      expect(Position.equals({ row: 4, col: 4 }, { row: 4, col: 3 })).toBe(false);
    });

    test('should handle null or undefined', () => {
      expect(Position.equals(null, { row: 4, col: 4 })).toBe(false);
      expect(Position.equals({ row: 4, col: 4 }, null)).toBe(false);
      expect(Position.equals(null, null)).toBe(false);
    });
  });

  describe('create', () => {
    test('should create a position object', () => {
      expect(Position.create(4, 4)).toEqual({ row: 4, col: 4 });
    });
  });

  describe('add', () => {
    test('should add two positions', () => {
      expect(Position.add({ row: 4, col: 4 }, { row: 1, col: -1 })).toEqual({ row: 5, col: 3 });
    });
  });

  describe('distance', () => {
    test('should calculate Manhattan distance', () => {
      expect(Position.distance({ row: 0, col: 0 }, { row: 3, col: 4 })).toBe(7);
      expect(Position.distance({ row: 4, col: 4 }, { row: 4, col: 4 })).toBe(0);
    });
  });

  describe('getBetween', () => {
    test('should get positions between two positions', () => {
      const positions = Position.getBetween({ row: 0, col: 0 }, { row: 0, col: 3 });
      expect(positions).toEqual([
        { row: 0, col: 1 },
        { row: 0, col: 2 }
      ]);
    });

    test('should return empty array for adjacent positions', () => {
      const positions = Position.getBetween({ row: 0, col: 0 }, { row: 0, col: 1 });
      expect(positions).toEqual([]);
    });
  });
});

