/**
 * Tests for chess piece classes
 */

const {
    PieceType,
    PieceColor,
    Pawn,
    Rook,
    Knight,
    Bishop,
    Queen,
    King,
    createPiece,
    getPieceValue
} = require('./pieces');

// Mock Position class for tests
class Position {
    static isValid(row, col) {
        return row >= 0 && row <= 7 && col >= 0 && col <= 7;
    }
}

describe('Piece Values', () => {
    test('should return correct piece values', () => {
        expect(getPieceValue('pawn')).toBe(1);
        expect(getPieceValue('knight')).toBe(3);
        expect(getPieceValue('bishop')).toBe(3);
        expect(getPieceValue('rook')).toBe(5);
        expect(getPieceValue('queen')).toBe(9);
        expect(getPieceValue('king')).toBe(0);
    });
});

describe('Pawn', () => {
    test('should create a white pawn', () => {
        const pawn = new Pawn(PieceColor.WHITE, 6, 4);
        expect(pawn.type).toBe(PieceType.PAWN);
        expect(pawn.color).toBe(PieceColor.WHITE);
        expect(pawn.row).toBe(6);
        expect(pawn.col).toBe(4);
        expect(pawn.direction).toBe(-1);
        expect(pawn.startRow).toBe(6);
    });

    test('should create a black pawn', () => {
        const pawn = new Pawn(PieceColor.BLACK, 1, 4);
        expect(pawn.type).toBe(PieceType.PAWN);
        expect(pawn.color).toBe(PieceColor.BLACK);
        expect(pawn.direction).toBe(1);
        expect(pawn.startRow).toBe(1);
    });

    test('should clone a pawn', () => {
        const pawn = new Pawn(PieceColor.WHITE, 6, 4);
        pawn.hasMoved = true;
        const cloned = pawn.clone();
        expect(cloned.type).toBe(pawn.type);
        expect(cloned.color).toBe(pawn.color);
        expect(cloned.hasMoved).toBe(true);
    });
});

describe('Rook', () => {
    test('should create a rook', () => {
        const rook = new Rook(PieceColor.WHITE, 7, 0);
        expect(rook.type).toBe(PieceType.ROOK);
        expect(rook.color).toBe(PieceColor.WHITE);
    });

    test('should clone a rook', () => {
        const rook = new Rook(PieceColor.WHITE, 7, 0);
        rook.hasMoved = true;
        const cloned = rook.clone();
        expect(cloned.hasMoved).toBe(true);
    });
});

describe('Knight', () => {
    test('should create a knight', () => {
        const knight = new Knight(PieceColor.WHITE, 7, 1);
        expect(knight.type).toBe(PieceType.KNIGHT);
        expect(knight.color).toBe(PieceColor.WHITE);
    });

    test('should clone a knight', () => {
        const knight = new Knight(PieceColor.WHITE, 7, 1);
        const cloned = knight.clone();
        expect(cloned.type).toBe(knight.type);
    });
});

describe('Bishop', () => {
    test('should create a bishop', () => {
        const bishop = new Bishop(PieceColor.WHITE, 7, 2);
        expect(bishop.type).toBe(PieceType.BISHOP);
        expect(bishop.color).toBe(PieceColor.WHITE);
    });
});

describe('Queen', () => {
    test('should create a queen', () => {
        const queen = new Queen(PieceColor.WHITE, 7, 3);
        expect(queen.type).toBe(PieceType.QUEEN);
        expect(queen.color).toBe(PieceColor.WHITE);
    });
});

describe('King', () => {
    test('should create a king', () => {
        const king = new King(PieceColor.WHITE, 7, 4);
        expect(king.type).toBe(PieceType.KING);
        expect(king.color).toBe(PieceColor.WHITE);
    });

    test('should clone a king', () => {
        const king = new King(PieceColor.WHITE, 7, 4);
        king.hasMoved = true;
        const cloned = king.clone();
        expect(cloned.hasMoved).toBe(true);
    });
});

describe('createPiece', () => {
    test('should create all piece types', () => {
        expect(createPiece(PieceColor.WHITE, PieceType.PAWN, 6, 4)).toBeInstanceOf(Pawn);
        expect(createPiece(PieceColor.WHITE, PieceType.ROOK, 7, 0)).toBeInstanceOf(Rook);
        expect(createPiece(PieceColor.WHITE, PieceType.KNIGHT, 7, 1)).toBeInstanceOf(Knight);
        expect(createPiece(PieceColor.WHITE, PieceType.BISHOP, 7, 2)).toBeInstanceOf(Bishop);
        expect(createPiece(PieceColor.WHITE, PieceType.QUEEN, 7, 3)).toBeInstanceOf(Queen);
        expect(createPiece(PieceColor.WHITE, PieceType.KING, 7, 4)).toBeInstanceOf(King);
    });

    test('should throw error for unknown piece type', () => {
        expect(() => createPiece(PieceColor.WHITE, 'invalid', 0, 0)).toThrow('Unknown piece type');
    });
});

